import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as e,f as n}from"./app-f83986bb.js";const i={},l=n(`<h1 id="vue" tabindex="-1"><a class="header-anchor" href="#vue" aria-hidden="true">#</a> vue</h1><h2 id="状态" tabindex="-1"><a class="header-anchor" href="#状态" aria-hidden="true">#</a> 状态</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki light-plus" style="background-color:#FFFFFF;" tabindex="0"><code><span class="line"><span style="color:#000000;">vuex是vue中的状态管理模式，统一管理多个组件共享的状态。</span></span>
<span class="line"><span style="color:#000000;">vuex状态管理模式的核心是store实例相当于应用的仓库，主要有四种属性：</span></span>
<span class="line"><span style="color:#000000;">state对象，多组件共享的状态，通过this.$store.的方式或通过辅助函数mapState将state属性映射到组件的计算属性</span></span>
<span class="line"><span style="color:#000000;">getters属性，类似于vue的计算属性，它会根据依赖的改变实时变更getter属性的值，即vuex的状态存储是响应式的，通过辅助函数mapGetter将getter属性映射到组件的计算属性</span></span>
<span class="line"><span style="color:#000000;">mutations属性类型于有名称的事件，通过commmit方法触发，用于改变store中state的属性状态，通过辅助函数mapMutation将触发方法映射到组件的方法属性，注意mutations是</span></span>
<span class="line"><span style="color:#000000;">--同步的，即mutation事件中不可使用回调函数，因为判断不了回调函数何时执行，何时执行完成，进而无法及时变更store中state状态</span></span>
<span class="line"><span style="color:#000000;">万物皆对象，函数属性存放的是函数的地址</span></span>
<span class="line"><span style="color:#000000;">actions与mutations类似，用于触发mutations事件，且可以执行异步操作，使用await/async,其中dispatch可以处理action事件传回的promise对象，且自己也可以返回promise</span></span>
<span class="line"><span style="color:#000000;">--对象，调用then方法执行后续操作,，通过辅助函数mapActions将触发方法dispatch映射到组件的方法属性，</span></span>
<span class="line"><span style="color:#000000;">module模块可以解决state对象非常臃肿的问题，使用store.state.模块名.模块名.状态属性访问状态，模块中可以嵌套模块，带有命名空间的模块</span></span>
<span class="line"><span style="color:#000000;">可以通过将store实例放入vue根实例的方式将状态实例注入到每一个组件</span></span>
<span class="line"><span style="color:#000000;">双向绑定的数据对象的数据对象的数据类型，影响赋值</span></span>
<span class="line"><span style="color:#000000;">v-auth权限控制若放在元素首部，可能会失效</span></span>
<span class="line"><span style="color:#000000;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="通信" tabindex="-1"><a class="header-anchor" href="#通信" aria-hidden="true">#</a> 通信</h2><ul><li>axios</li><li>qs处理参数</li></ul><h2 id="异步" tabindex="-1"><a class="header-anchor" href="#异步" aria-hidden="true">#</a> 异步</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki light-plus" style="background-color:#FFFFFF;" tabindex="0"><code><span class="line"><span style="color:#000000;">promise对象本身是同步的，.then.catch方法是异步的</span></span>
<span class="line"><span style="color:#000000;">当promise对象创建完成后，其内部的executor函数会立即执行</span></span>
<span class="line"><span style="color:#000000;">通常在其中放入异步操作，使用resolve，reject告诉promise，改变状态</span></span>
<span class="line"><span style="color:#000000;">await，async，promise息息相关，await只能在async函数中使用，当执行到await时async函数会挂起，</span></span>
<span class="line"><span style="color:#000000;">等待await右侧的表达式返回promise或对象</span></span>
<span class="line"><span style="color:#000000;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="问题" tabindex="-1"><a class="header-anchor" href="#问题" aria-hidden="true">#</a> 问题</h2><h3 id="vue父子组件传值不刷新问题" tabindex="-1"><a class="header-anchor" href="#vue父子组件传值不刷新问题" aria-hidden="true">#</a> vue父子组件传值不刷新问题</h3><p>1、在父组件改变子组件的值后，立即调用子组件方法获取最新的值，结果获取不到，获取的是旧值 注意双向绑定和属性绑定的区别，以数据驱动的模型,数据改变组件刷新</p><p>解决方案：</p><ul><li>1、强制刷新数据，$set,v-if</li><li>2、在子组件中监听父组件传入的值，当值改变时进行操作</li><li>3、改变key的值</li><li>4、this.$nextTick,在组件渲染后执行</li><li>5、延时操作setTimeout</li></ul>`,12),t=[l];function r(c,p){return a(),e("div",null,t)}const u=s(i,[["render",r],["__file","vue.html.vue"]]);export{u as default};
